// Cache-aside pattern
async function getUser(userId: string) {
  const cached = await redis.get(`user:${userId}`);
  if (cached) return JSON.parse(cached); // Cache HIT

  const user = await db.findUser(userId);  // Cache MISS → DB
  await redis.setex(`user:${userId}`, 3600, JSON.stringify(user)); // Cache write + TTL
  return user;
}

